# setup-icone-ad-projetos.ps1
# Atualiza automaticamente o icone do PWA AD Projetos sem borda clara externa.
# Coloque este arquivo na raiz do projeto e execute pelo PowerShell.

$ErrorActionPreference = "Stop"

$projectRoot = Split-Path -Parent $MyInvocation.MyCommand.Path
Set-Location $projectRoot

$publicDir = Join-Path $projectRoot "public"
if (-not (Test-Path $publicDir)) {
  New-Item -ItemType Directory -Path $publicDir | Out-Null
}

Write-Host "Atualizando icones do AD Projetos..." -ForegroundColor Cyan

$icon64 = @"

"@

$icon180 = @"

"@

$icon192 = @"

"@

$icon512 = @"

"@

[System.Convert]::FromBase64String($icon64) | Set-Content -Path (Join-Path $publicDir "favicon.png") -Encoding Byte
[System.Convert]::FromBase64String($icon180) | Set-Content -Path (Join-Path $publicDir "apple-touch-icon.png") -Encoding Byte
[System.Convert]::FromBase64String($icon192) | Set-Content -Path (Join-Path $publicDir "icon-192.png") -Encoding Byte
[System.Convert]::FromBase64String($icon512) | Set-Content -Path (Join-Path $publicDir "icon-512.png") -Encoding Byte
[System.Convert]::FromBase64String($icon192) | Set-Content -Path (Join-Path $publicDir "maskable-icon-192.png") -Encoding Byte
[System.Convert]::FromBase64String($icon512) | Set-Content -Path (Join-Path $publicDir "maskable-icon-512.png") -Encoding Byte
[System.Convert]::FromBase64String($icon192) | Set-Content -Path (Join-Path $publicDir "logo192.png") -Encoding Byte
[System.Convert]::FromBase64String($icon512) | Set-Content -Path (Join-Path $publicDir "logo512.png") -Encoding Byte

$svgIcon = @'
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512">
  <rect width="512" height="512" fill="#2A170F"/>
  <rect x="399" y="41" width="82" height="82" rx="24" fill="#C48667"/>
  <text x="195" y="278" text-anchor="middle" font-family="Georgia,serif" font-size="172" font-weight="700" fill="#F4EEE7">AD</text>
  <text x="220" y="364" text-anchor="middle" font-family="Arial,sans-serif" font-size="34" font-weight="800" letter-spacing="3" fill="#F4EEE7">PROJETOS</text>
</svg>
'@

$svgIcon | Set-Content -Path (Join-Path $publicDir "vite.svg") -Encoding UTF8
$svgIcon | Set-Content -Path (Join-Path $publicDir "favicon.svg") -Encoding UTF8

# Remove manifest antigo para evitar conflito, mas recria em seguida.
Remove-Item (Join-Path $publicDir "site.webmanifest") -Force -ErrorAction SilentlyContinue
Remove-Item (Join-Path $projectRoot "vite.svg") -Force -ErrorAction SilentlyContinue

$manifestContent = @'
{
  "id": "/ad-projetos-v9",
  "name": "AD Projetos",
  "short_name": "AD Projetos",
  "description": "Alexandre Dias | Gestao de Projetos",
  "lang": "pt-BR",
  "start_url": "/",
  "scope": "/",
  "display": "standalone",
  "orientation": "portrait",
  "background_color": "#2A170F",
  "theme_color": "#2A170F",
  "icons": [
    {
      "src": "/icon-192.png?v=9",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "any"
    },
    {
      "src": "/icon-512.png?v=9",
      "sizes": "512x512",
      "type": "image/png",
      "purpose": "any"
    },
    {
      "src": "/maskable-icon-192.png?v=9",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "maskable"
    },
    {
      "src": "/maskable-icon-512.png?v=9",
      "sizes": "512x512",
      "type": "image/png",
      "purpose": "maskable"
    },
    {
      "src": "/apple-touch-icon.png?v=9",
      "sizes": "180x180",
      "type": "image/png"
    }
  ]
}
'@

$manifestPath = Join-Path $publicDir "manifest.webmanifest"
$manifestContent | Set-Content -Path $manifestPath -Encoding UTF8
$manifestContent | Set-Content -Path (Join-Path $publicDir "manifest.json") -Encoding UTF8

$indexPath = Join-Path $projectRoot "index.html"
if (Test-Path $indexPath) {
  Copy-Item $indexPath ($indexPath + ".backup") -Force
}

$indexContent = @'
<!doctype html>
<html lang="pt-BR">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover" />

    <title>AD Projetos</title>
    <meta name="description" content="Alexandre Dias | Gestao de Projetos" />
    <meta name="theme-color" content="#2A170F" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-status-bar-style" content="default" />
    <meta name="apple-mobile-web-app-title" content="AD Projetos" />
    <meta name="mobile-web-app-capable" content="yes" />

    <link rel="icon" type="image/png" sizes="64x64" href="/favicon.png?v=9" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg?v=9" />
    <link rel="apple-touch-icon" href="/apple-touch-icon.png?v=9" />
    <link rel="manifest" href="/manifest.webmanifest?v=9" />
  </head>

  <body>
    <div id="root"></div>
    <script type="module" src="/src/main.jsx"></script>
  </body>
</html>
'@

$indexContent | Set-Content -Path $indexPath -Encoding UTF8

Write-Host ""
Write-Host "OK! Icone AD Projetos atualizado sem borda clara externa." -ForegroundColor Green
Write-Host ""
Write-Host "Agora rode:" -ForegroundColor Cyan
Write-Host "git add ."
Write-Host 'git commit -m "Corrigir icone AD Projetos sem borda clara"'
Write-Host "git push"
Write-Host ""
Write-Host "Depois espere a Vercel ficar Ready e reinstale o app pelo dominio gestao-projetos-ruby.vercel.app." -ForegroundColor Yellow
